#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(const int &p){if(p>9)print(p/10);putchar(p%10+'0');}
inline void pt(const int &p,const char &ch='\n'){print(p<0?putchar('-'),-p:p);putchar(ch);}
const int N=50;bool dp[N][N][N][N];int n,a[N][5];//dp[i][j][k][l] -- 分别已经选了i,j,k,l个糖可不可行; 
bool jud[25];int num,ans;inline void chkmax(int &x,const int &y){x<y?x=y:0;}
inline void dfs(int i,int j,int k,int l)
{
//	if(i==6&&j==i&&k==j&&l==k){rep(1,10,i)printf("%d ",jud[i]);printf("%d\n",num);}
//	printf("%d %d %d %d %d\n",i,j,k,l,n);
	if(num==5)return;if(dp[i][j][k][l])return;dp[i][j][k][l]=true;
	if(i+j+k+l-num-4>ans)ans=i+j+k+l-num-4;//,printf("%d %d %d %d\n",i,j,k,l);
	if(i<=n)
	{
//		puts("???");
		if(jud[a[i][1]]){jud[a[i][1]]=false;--num;dfs(i+1,j,k,l);++num;jud[a[i][1]]=true;}
		else {jud[a[i][1]]=true;++num;dfs(i+1,j,k,l);--num;jud[a[i][1]]=false;}
	}
	if(j<=n)
	{
		if(jud[a[j][2]]){jud[a[j][2]]=false;--num;dfs(i,j+1,k,l);++num;jud[a[j][2]]=true;}
		else {jud[a[j][2]]=true;++num;dfs(i,j+1,k,l);--num;jud[a[j][2]]=false;}
	}
	if(k<=n)
	{
		if(jud[a[k][3]]){jud[a[k][3]]=false;--num;dfs(i,j,k+1,l);++num;jud[a[k][3]]=true;}
		else {jud[a[k][3]]=true;++num;dfs(i,j,k+1,l);--num;jud[a[k][3]]=false;}
	}
	if(l<=n)
	{
		if(jud[a[l][4]]){jud[a[l][4]]=false;--num;dfs(i,j,k,l+1);++num;jud[a[l][4]]=true;}
		else {jud[a[l][4]]=true;++num;dfs(i,j,k,l+1);--num;jud[a[l][4]]=false;}
	}
}
inline void Solve()
{
	memset(dp,0,sizeof(dp));ans=0;
	rep(1,n,i)rep(1,4,j)a[i][j]=read();
	dfs(1,1,1,1);pt(ans>>1);
}
int main(){while((n=read()))Solve();}
